/**
 * 类名合并工具（uts 兼容子集）
 *
 * 设计原则：
 *  - 仅接受 string | object | array | 任何 falsy
 *  - 数字（含 0）一律视为非法输入并跳过（与 uts 严格类型对齐）
 *  - 自动去重 + 保持首次出现顺序
 *  - 多余空格规范化为单空格
 *
 * 与 clsx 区别：
 *  - clsx 会输出非零数字；cn 跳过所有数字（uts 中类名只允许字符串）
 *  - cn 始终去重
 */

export type ClassValue =
  | string
  | false
  | null
  | undefined
  | ClassDictionary
  | ClassArray;

export interface ClassDictionary {
  [key: string]: unknown;
}

export type ClassArray = ClassValue[];

function pushTokens(target: string[], raw: string): void {
  // 规范化：把任意空白拆成 token 数组
  const tokens = raw.split(/\s+/);
  for (let i = 0; i < tokens.length; i++) {
    const t = tokens[i];
    if (t.length > 0 && target.indexOf(t) === -1) {
      target.push(t);
    }
  }
}

function walk(value: ClassValue, target: string[]): void {
  if (value === null || value === undefined || value === false || value === '') {
    return;
  }

  if (typeof value === 'string') {
    pushTokens(target, value);
    return;
  }

  if (Array.isArray(value)) {
    for (let i = 0; i < value.length; i++) {
      walk(value[i] as ClassValue, target);
    }
    return;
  }

  if (typeof value === 'object') {
    const dict = value as ClassDictionary;
    for (const key in dict) {
      if (Object.prototype.hasOwnProperty.call(dict, key) && dict[key]) {
        pushTokens(target, key);
      }
    }
    return;
  }

  // 其他类型（number、function 等）按契约跳过
}

export function cn(...inputs: ClassValue[]): string {
  const tokens: string[] = [];
  for (let i = 0; i < inputs.length; i++) {
    walk(inputs[i], tokens);
  }
  return tokens.join(' ');
}

export default cn;

/**
 * cva（class-variance-authority）的极简实现，针对 uts/uvue 场景适配。
 *
 * 与社区 cva 的差异：
 *  - 不依赖 clsx，直接用本包的 cn
 *  - 类型签名更窄，避免 uts 不支持的复杂条件类型
 *  - boolean 变体通过 'true' / 'false' 字符串键映射
 *
 * 使用：
 *   const button = cva('t-button', {
 *     variants: {
 *       variant: { primary: 't-button--primary', outline: 't-button--outline' },
 *       size:    { sm: 't-button--sm', md: 't-button--md' },
 *       block:   { true: 't-button--block' },
 *     },
 *     compoundVariants: [
 *       { variant: 'primary', size: 'lg', class: 'font-bold' }
 *     ],
 *     defaultVariants: { variant: 'primary', size: 'md' }
 *   });
 *   button({ variant: 'outline', class: 'mt-2' });
 */

import { cn, type ClassValue } from './cn';

export type VariantsConfig = Record<string, Record<string, string>>;

export type VariantProps<C extends VariantsConfig> = {
  [K in keyof C]?: keyof C[K] | boolean;
} & {
  class?: ClassValue;
};

export interface CvaConfig<C extends VariantsConfig> {
  variants?: C;
  defaultVariants?: { [K in keyof C]?: keyof C[K] | boolean };
  compoundVariants?: Array<
    { [K in keyof C]?: keyof C[K] | boolean } & { class: ClassValue }
  >;
}

export type CvaFn<C extends VariantsConfig> = (props?: VariantProps<C>) => string;

function normalizeKey(value: unknown): string {
  if (value === true) return 'true';
  if (value === false) return 'false';
  return String(value);
}

export function cva<C extends VariantsConfig>(
  base: string,
  config: CvaConfig<C> = {},
): CvaFn<C> {
  const variants = (config.variants ?? {}) as VariantsConfig;
  const defaults = (config.defaultVariants ?? {}) as Record<string, unknown>;
  const compounds = config.compoundVariants ?? [];

  return (props?: VariantProps<C>): string => {
    const p = (props ?? {}) as Record<string, unknown>;
    const tokens: ClassValue[] = [base];

    // 1. 基础变体
    for (const variantKey in variants) {
      if (!Object.prototype.hasOwnProperty.call(variants, variantKey)) continue;
      const variantMap = variants[variantKey];

      const passed = p[variantKey];
      let chosenKey: string | undefined;

      if (passed !== undefined && variantMap[normalizeKey(passed)] !== undefined) {
        chosenKey = normalizeKey(passed);
      } else if (defaults[variantKey] !== undefined) {
        chosenKey = normalizeKey(defaults[variantKey]);
      }

      if (chosenKey !== undefined && variantMap[chosenKey] !== undefined) {
        tokens.push(variantMap[chosenKey]);
      }
    }

    // 2. 复合变体
    for (let i = 0; i < compounds.length; i++) {
      const rule = compounds[i] as Record<string, unknown> & { class: ClassValue };
      let matched = true;
      for (const k in rule) {
        if (k === 'class') continue;
        const expected = normalizeKey(rule[k]);
        const actualRaw = p[k] !== undefined ? p[k] : defaults[k];
        if (actualRaw === undefined || normalizeKey(actualRaw) !== expected) {
          matched = false;
          break;
        }
      }
      if (matched) {
        tokens.push(rule.class);
      }
    }

    // 3. 透传 class
    if (p.class !== undefined) {
      tokens.push(p.class as ClassValue);
    }

    return cn(...tokens);
  };
}

export default cva;

/**
 * 文本相关工具（uts 兼容子集）
 *
 * - getCharacterLength：按 'maxlength' 或 'maxcharacter' 计算并截取字符串。
 *   `maxcharacter` 下一个汉字 / 高位字符算 2 个长度；
 *   `maxlength` 下任意字符均算 1。
 *
 * 与 packages/uniapp-components/common/utils.js 的 getCharacterLength 对齐，
 * 行为完全一致，便于双端表现统一。
 */

export type CharCountMode = 'maxlength' | 'maxcharacter';

export interface CharCountResult {
  /** 计数长度（受 mode 影响） */
  length: number;
  /** 截断后的字符串；当 char 未超出限制时即原值 */
  characters: string;
}

/**
 * 计算字符串字符长度并可截取
 *
 * @param type - 计数模式
 * @param char - 输入文本（null/undefined 视为空串）
 * @param max  - 上限；<=0 时不截断，仅返回长度
 */
export function getCharacterLength(
  type: CharCountMode,
  char: string | null | undefined,
  max: number,
): CharCountResult {
  const str = char == null ? '' : String(char);

  if (str.length === 0) {
    return { length: 0, characters: '' };
  }

  if (type === 'maxcharacter') {
    let len = 0;
    for (let i = 0; i < str.length; i += 1) {
      // 高位字符（中文 / emoji 高代理对 / `^` 强制 2 长度）按 2 计
      const code = str.charCodeAt(i);
      const currentStringLength = code > 127 || code === 94 ? 2 : 1;
      if (max > 0 && len + currentStringLength > max) {
        return { length: len, characters: str.slice(0, i) };
      }
      len += currentStringLength;
    }
    return { length: len, characters: str };
  }

  // maxlength
  if (max > 0 && str.length > max) {
    return { length: max, characters: str.slice(0, max) };
  }
  return { length: str.length, characters: str };
}

export default getCharacterLength;
